import React from 'react';
import type { Review } from '@/lib/reviews';
import ScoreBadge from './ScoreBadge';

interface ArticleCardProps {
  review: Review;
  featured?: boolean;
}

export default function ArticleCard({ review, featured = false }: ArticleCardProps) {
  const { title, category, score, excerpt, imageUrl, developer, year } = review;

  return (
    <article
      tabIndex={0}
      role="button"
      aria-label={`${title}, score ${score} out of 10, ${category}`}
      style={{
        backgroundColor: '#1A1A1A',
        border: '1px solid #2A2A2A',
        borderRadius: 0,
        overflow: 'hidden',
        cursor: 'pointer',
        display: 'flex',
        flexDirection: 'column',
        transition: 'border-color 200ms ease-out, transform 200ms ease-out',
        width: '100%',
      }}
      onMouseEnter={(e: React.MouseEvent<HTMLElement>) => {
        e.currentTarget.style.borderColor = '#EF9F27';
        e.currentTarget.style.transform = 'translateY(-2px)';
      }}
      onMouseLeave={(e: React.MouseEvent<HTMLElement>) => {
        e.currentTarget.style.borderColor = '#2A2A2A';
        e.currentTarget.style.transform = 'translateY(0)';
      }}
    >
      {/* Thumbnail */}
      <div style={{ position: 'relative', aspectRatio: featured ? '21/9' : '16/9', overflow: 'hidden' }}>
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img
          src={imageUrl}
          alt={`${title} screenshot`}
          style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }}
          loading="lazy"
        />
        {/* Score badge over image */}
        <div style={{ position: 'absolute', top: 8, right: 8 }}>
          <ScoreBadge score={score} size="sm" />
        </div>
      </div>

      {/* Content */}
      <div style={{ padding: 16, flex: 1, display: 'flex', flexDirection: 'column', gap: 8 }}>
        {/* Genre */}
        <span
          style={{
            fontFamily: "'Public Sans', system-ui, sans-serif",
            fontSize: 10,
            fontWeight: 600,
            textTransform: 'uppercase',
            letterSpacing: '0.12em',
            color: '#EF9F27',
          }}
        >
          {category}
        </span>

        {/* Title */}
        <h2
          style={{
            fontFamily: "'Libre Bodoni', Georgia, serif",
            fontSize: featured ? 22 : 16,
            fontWeight: 700,
            lineHeight: 1.25,
            color: '#F0EBE0',
          }}
        >
          {title}
        </h2>

        {/* Excerpt — only on featured */}
        {featured && (
          <p
            style={{
              fontFamily: "'Public Sans', system-ui, sans-serif",
              fontSize: 14,
              lineHeight: 1.6,
              color: '#888888',
              flex: 1,
            }}
          >
            {excerpt}
          </p>
        )}

        {/* Meta */}
        <p
          style={{
            fontFamily: "'Public Sans', system-ui, sans-serif",
            fontSize: 11,
            color: '#444444',
            textTransform: 'uppercase',
            letterSpacing: '0.06em',
            marginTop: 'auto',
          }}
        >
          {developer} · {year}
        </p>
      </div>
    </article>
  );
}
